// // This module decrements a 4-bit binary counter on the positive edge of the clock signal and resets to 7 when the reset signal is high.
module binary_counter (
  input clk,
  input rst,
  output reg [3:0] q);always @(posedge clk or posedge rst) begin
  if (rst) 
    q <= 4'b0000;
  else 
    q <= q + 1;
end

endmodule
